CREATE TABLE IF NOT EXISTS commerce_apps (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, app_key TEXT NOT NULL, name TEXT NOT NULL, developer_name TEXT NOT NULL DEFAULT '', app_url TEXT NOT NULL DEFAULT '', webhook_url TEXT NOT NULL DEFAULT '', requested_scopes_json TEXT NOT NULL DEFAULT '[]', status TEXT NOT NULL DEFAULT 'private', pricing_json TEXT NOT NULL DEFAULT '{}', created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, UNIQUE (merchant_id, app_key));
CREATE TABLE IF NOT EXISTS app_installations (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, app_id TEXT NOT NULL, granted_scopes_json TEXT NOT NULL DEFAULT '[]', status TEXT NOT NULL DEFAULT 'installed', config_json TEXT NOT NULL DEFAULT '{}', installed_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, FOREIGN KEY (app_id) REFERENCES commerce_apps(id) ON DELETE CASCADE, UNIQUE (merchant_id, app_id));
CREATE TABLE IF NOT EXISTS api_access_tokens (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, label TEXT NOT NULL, token_hash TEXT NOT NULL, secret_preview TEXT NOT NULL DEFAULT '', scopes_json TEXT NOT NULL DEFAULT '[]', status TEXT NOT NULL DEFAULT 'active', expires_at TEXT, last_used_at TEXT, created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, revoked_at TEXT, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, UNIQUE (token_hash));
CREATE TABLE IF NOT EXISTS custom_domains (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, hostname TEXT NOT NULL, mode TEXT NOT NULL DEFAULT 'primary', status TEXT NOT NULL DEFAULT 'pending', verification_token TEXT NOT NULL, verification_record_name TEXT NOT NULL DEFAULT '', verification_record_value TEXT NOT NULL DEFAULT '', tls_mode TEXT NOT NULL DEFAULT 'auto', last_checked_at TEXT, created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, UNIQUE (merchant_id, hostname));
CREATE TABLE IF NOT EXISTS redirect_rules (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, from_path TEXT NOT NULL, to_path TEXT NOT NULL, status_code INTEGER NOT NULL DEFAULT 301, active INTEGER NOT NULL DEFAULT 1, hit_count INTEGER NOT NULL DEFAULT 0, created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, UNIQUE (merchant_id, from_path));
CREATE TABLE IF NOT EXISTS seo_entries (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, resource_type TEXT NOT NULL DEFAULT 'custom', resource_id TEXT NOT NULL DEFAULT '', path TEXT NOT NULL, title TEXT NOT NULL DEFAULT '', description TEXT NOT NULL DEFAULT '', image_url TEXT NOT NULL DEFAULT '', canonical_url TEXT NOT NULL DEFAULT '', robots TEXT NOT NULL DEFAULT 'index,follow', schema_json TEXT NOT NULL DEFAULT '{}', created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, UNIQUE (merchant_id, path));
CREATE TABLE IF NOT EXISTS payment_disputes (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, order_id TEXT, provider TEXT NOT NULL DEFAULT 'stripe', provider_dispute_id TEXT NOT NULL DEFAULT '', amount_cents INTEGER NOT NULL DEFAULT 0, currency TEXT NOT NULL DEFAULT 'USD', reason TEXT NOT NULL DEFAULT 'fraudulent', status TEXT NOT NULL DEFAULT 'needs_response', due_at TEXT NOT NULL DEFAULT '', evidence_due_by TEXT NOT NULL DEFAULT '', created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, FOREIGN KEY (order_id) REFERENCES orders(id) ON DELETE SET NULL);
CREATE TABLE IF NOT EXISTS dispute_evidence (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, dispute_id TEXT NOT NULL, evidence_json TEXT NOT NULL DEFAULT '{}', evidence_score INTEGER NOT NULL DEFAULT 0, status TEXT NOT NULL DEFAULT 'draft', submitted_at TEXT, created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, FOREIGN KEY (dispute_id) REFERENCES payment_disputes(id) ON DELETE CASCADE);
CREATE INDEX IF NOT EXISTS idx_commerce_apps_merchant ON commerce_apps (merchant_id, status, app_key);
CREATE INDEX IF NOT EXISTS idx_app_installations_merchant ON app_installations (merchant_id, status, installed_at DESC);
CREATE INDEX IF NOT EXISTS idx_api_tokens_merchant ON api_access_tokens (merchant_id, status, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_custom_domains_merchant ON custom_domains (merchant_id, status, hostname);
CREATE INDEX IF NOT EXISTS idx_redirect_rules_merchant ON redirect_rules (merchant_id, active, from_path);
CREATE INDEX IF NOT EXISTS idx_seo_entries_merchant ON seo_entries (merchant_id, resource_type, path);
CREATE INDEX IF NOT EXISTS idx_payment_disputes_merchant ON payment_disputes (merchant_id, status, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_dispute_evidence_dispute ON dispute_evidence (merchant_id, dispute_id, created_at DESC);
